class GameDataController {
  constructor() {
    // ...existing code...
  }

  getData() {
    return this.data;
  }

  setData(newData) {
    this.data = { ...this.data, ...newData };
    // Notify Captivate (legacy)
    if (window.Captivate && typeof window.Captivate.dataUpdated === 'function') {
      window.Captivate.dataUpdated();
    }
    // Notify Captivate (ServiceHandler API)
    this.sendToCaptivate(this.data);
  }

  sendToCaptivate(data) {
    if (
      window.Captivate &&
      window.Captivate.ServiceHandler &&
      typeof window.Captivate.ServiceHandler.scheduleAction === 'function'
    ) {
      window.Captivate.ServiceHandler.scheduleAction('updateGameData', data);
      console.log('Sent data to Captivate via ServiceHandler:', data);
    } else {
      console.warn('Captivate ServiceHandler not available.');
    }
  }

  updateFromGameState(gameState) {
    // ...existing mapping logic...
    const mapped = { /* ...same as before... */ };
    this.setData(mapped);
  }

  manualUpdate() {
    // Notify Captivate (legacy)
    if (window.Captivate && typeof window.Captivate.dataUpdated === 'function') {
      window.Captivate.dataUpdated();
      console.log('Manual Captivate dataUpdated() called.');
    } else {
      console.warn('Captivate not available on window.');
    }
    // Notify Captivate (ServiceHandler API)
    this.sendToCaptivate(this.data);
  }
}

window.gameDataController = new GameDataController();
window.manualCaptivateUpdate = () => window.gameDataController.manualUpdate();
export default window.gameDataController;
